export function getDefaultRaylibLibraryName(): string {
  switch (Deno.build.os) {
    case "windows": return "raylib.dll";
    case "darwin": return "libraylib.dylib";
    default: return "libraylib.so";
  }
}

let raylibLibrary: Deno.DynamicLibrary<RaylibSymbols> | null = null;

export function loadRaylib(path = getDefaultRaylibLibraryName()): Deno.DynamicLibrary<RaylibSymbols> {
  raylibLibrary ??= Deno.dlopen(path, symbolDefinitions);
  return raylibLibrary;
}

export function unloadRaylib(): void {
  if (raylibLibrary !== null) {
    raylibLibrary.close();
    raylibLibrary = null;
  }
}

export function isRaylibLoaded(): boolean {
  return raylibLibrary !== null;
}

function requireRaylibLibrary(): Deno.DynamicLibrary<RaylibSymbols> {
  if (raylibLibrary === null) {
    throw new Error("Raylib library not loaded. Call loadRaylib() first.");
  }
  return raylibLibrary;
}

export type RaylibLoadedSymbols = Deno.DynamicLibrary<RaylibSymbols>["symbols"];

export function getRaylibLibrary(): Deno.DynamicLibrary<RaylibSymbols> {
  return requireRaylibLibrary();
}

export function getRaylibSymbols(): RaylibLoadedSymbols {
  return requireRaylibLibrary().symbols;
}

